from flask import Flask, redirect, url_for, request, render_template
import os
from datetime import datetime
from threading import Lock

app = Flask(__name__)

DATA_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'data')


# File lock for thread safety
_file_lock = Lock()

# Utility functions

def read_users():
    users = {}
    path = os.path.join(DATA_DIR, 'users.txt')
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 4:
                    continue
                username, email, phone, full_name = parts
                users[username] = {'username': username, 'email': email, 'phone': phone, 'full_name': full_name}
    except FileNotFoundError:
        pass
    return users


def read_menu():
    dishes = []
    path = os.path.join(DATA_DIR, 'menu.txt')
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 8:
                    continue
                try:
                    dish_id = int(parts[0])
                    price = float(parts[3])
                    avg_rating = float(parts[7])
                    dish = {
                        'dish_id': dish_id,
                        'name': parts[1],
                        'category': parts[2],
                        'price': price,
                        'description': parts[4],
                        'ingredients': parts[5],
                        'dietary': parts[6],
                        'avg_rating': avg_rating
                    }
                    dishes.append(dish)
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return dishes


def read_reservations():
    reservations = []
    path = os.path.join(DATA_DIR, 'reservations.txt')
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 10:
                    continue
                try:
                    reservation_id = int(parts[0])
                    party_size = int(parts[5])
                    reservation = {
                        'reservation_id': reservation_id,
                        'username': parts[1],
                        'guest_name': parts[2],
                        'phone': parts[3],
                        'email': parts[4],
                        'party_size': party_size,
                        'date': parts[6],
                        'time': parts[7],
                        'special_requests': parts[8],
                        'status': parts[9]
                    }
                    reservations.append(reservation)
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return reservations


def write_reservations(reservations):
    path = os.path.join(DATA_DIR, 'reservations.txt')
    with _file_lock:
        with open(path, 'w', encoding='utf-8') as f:
            for r in reservations:
                line = '|'.join([
                    str(r['reservation_id']),
                    r['username'],
                    r['guest_name'],
                    r['phone'],
                    r['email'],
                    str(r['party_size']),
                    r['date'],
                    r['time'],
                    r['special_requests'],
                    r['status']
                ])
                f.write(line + '\n')


def read_waitlist():
    waitlist = []
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 5:
                    continue
                try:
                    waitlist_id = int(parts[0])
                    party_size = int(parts[2])
                    join_time = parts[3]
                    status = parts[4]
                    entry = {
                        'waitlist_id': waitlist_id,
                        'username': parts[1],
                        'party_size': party_size,
                        'join_time': join_time,
                        'status': status
                    }
                    waitlist.append(entry)
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return waitlist


def write_waitlist(waitlist):
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    with _file_lock:
        with open(path, 'w', encoding='utf-8') as f:
            for w in waitlist:
                line = '|'.join([
                    str(w['waitlist_id']),
                    w['username'],
                    str(w['party_size']),
                    w['join_time'],
                    w['status']
                ])
                f.write(line + '\n')


def read_reviews():
    reviews = []
    path = os.path.join(DATA_DIR, 'reviews.txt')
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 6:
                    continue
                try:
                    review_id = int(parts[0])
                    dish_id = int(parts[2])
                    rating = int(parts[3])
                    review = {
                        'review_id': review_id,
                        'username': parts[1],
                        'dish_id': dish_id,
                        'rating': rating,
                        'review_text': parts[4],
                        'review_date': parts[5]
                    }
                    reviews.append(review)
                except ValueError:
                    continue
    except FileNotFoundError:
        pass
    return reviews


def write_reviews(reviews):
    path = os.path.join(DATA_DIR, 'reviews.txt')
    with _file_lock:
        with open(path, 'w', encoding='utf-8') as f:
            for r in reviews:
                line = '|'.join([
                    str(r['review_id']),
                    r['username'],
                    str(r['dish_id']),
                    str(r['rating']),
                    r['review_text'],
                    r['review_date']
                ])
                f.write(line + '\n')


